-- Carga Uber Eats enero 2026 -> channel_settlement_order (Capa C). Idempotente.
on conflict (account_id, import_key) do nothing;

-- verificacion
select source, count(*) pedidos, round(sum(commission)) comision, round(sum(promo_product)) promo, round(sum(net_payout)) pago
from public.channel_settlement_order where account_id='51ad1792-6629-4ef7-833a-b57b09a86710' and source='uber_emea' group by source;
